  const result = { planned: [], working: [], done: [] };
  let inOpen = false;
  let inClosed = false;

  const today = new Date().toISOString().split("T")[0];
  const standupPath = standupPathArg || `${LIVE_REPO_PATH}/standups/${today}.md`;
  const standup = fs.existsSync(standupPath) ? fs.readFileSync(standupPath, "utf8") : "";

  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith("### OPEN")) { inOpen = true; inClosed = false; continue; }
    if (trimmed.startsWith("### CLOSED")) { inOpen = false; inClosed = true; continue; }
    if (trimmed.startsWith("## ") || (inOpen && trimmed === "")) { inOpen = false; inClosed = false; }

    if (inOpen && trimmed.startsWith("|")) {
      const cells = trimmed.split("|").map(c => c.trim()).filter(Boolean);
      const isSeparator = cells.every(c => /^:?-+:?$/.test(c));
      if (cells.length < 4 || cells[0].toLowerCase().includes("ticket") || isSeparator) continue;

      const id = cells[0].replace(/\*/g, "").replace("#", "");
      if (!/\d/.test(id)) continue;
      const title = cells[1];
      const owner = cells[2];
      const status = cells[3]; // in_work, planned, merged

      const ticket = { id, title, owner, status };
      if (status === "in_work" || status === "merged") result.working.push(ticket);
      else result.planned.push(ticket);
    }

    if (inClosed && trimmed.startsWith("-")) {
      // Format: - **#N**: Description -- Owner.
      const match = trimmed.match(/-\s*\*\*#(\d+)\*\*:\s*([^-]+)--\s*(\w+)/);
      if (match) {
        const id = match[1];
        const title = match[2].trim();
        const owner = match[3].trim();

        // Check if completed today via standup
        const isDoneToday = standup.includes(`#${id}`) || standup.includes(`Ticket #${id}`);
        if (isDoneToday) {
          result.done.push({ id, title, owner, status: "completed", date: new Date().toISOString() });
        }
      }
    }
  }
  return result;
